function Education() {
  return (
    <div className="education">
      <h1>Education</h1>
      <ul>
        <li> Sept 2024 - April 2025 - College Diploma in Software Engineering Technician 
            - Centennial College</li>
            <li> Sept 2019-April 2020 - Certificate in Pre-Health Science
             - Durham College, Oshawa, ON </li>
        <li> Sept 2015-June 2019 - High School Diploma 
            - O'Neill Collegiate and Vocational Institute </li>
      </ul>
    </div>
  );
}

export default Education;
